<?php $editing=!empty($user['id']);$groups=['dashboard'=>'Prezentare generală','orders'=>'Comenzi','products'=>'Produse','categories'=>'Categorii și colecții','customers'=>'Clienți','shipping'=>'Livrare și AWB','billing'=>'Facturare','cms'=>'Pagini și texte','atelier'=>'Atelier','seo'=>'SEO','reports'=>'Rapoarte','audit'=>'Audit','settings'=>'Setările magazinului'];$byGroup=[];foreach($permissions as $permission){$prefix=explode('.',$permission['name'],2)[0];$byGroup[$prefix][]=$permission;} ?>
<section class="admin-page-head"><div><p class="eyebrow">ECHIPĂ / <?= $editing?'EDITARE':'CONT NOU' ?></p><h1><?= $editing?'Editează accesul':'Utilizator nou' ?></h1><p>Poți schimba ulterior orice permisiune sau poți bloca temporar contul.</p></div><a class="admin-button secondary" href="<?= e(url('/admin/utilizatori')) ?>">Înapoi la echipă</a></section>
<form class="admin-form-layout staff-form" method="post" action="<?= e(url($editing?'/admin/utilizatori/'.$user['id']:'/admin/utilizatori')) ?>"><?= csrf_field() ?><div><section class="admin-panel"><p class="eyebrow">PASUL 1</p><h2>Datele persoanei</h2><div class="admin-form-grid"><label>Prenume<input name="first_name" required autocomplete="given-name" value="<?= e($user['first_name']??'') ?>"></label><label>Nume<input name="last_name" required autocomplete="family-name" value="<?= e($user['last_name']??'') ?>"></label><label class="wide">Email pentru conectare<input type="email" name="email" required autocomplete="email" value="<?= e($user['email']??'') ?>"></label><label class="wide"><?= $editing?'Parolă nouă (lasă gol pentru a o păstra)':'Parolă inițială' ?><input type="password" name="password" <?= $editing?'':'required minlength="10"' ?> autocomplete="new-password"></label></div></section><section class="admin-panel"><p class="eyebrow">PASUL 2</p><div class="panel-head"><div><h2>Ce poate face în magazin</h2><p>Bifează numai zonele de care persoana are nevoie.</p></div><button class="admin-button secondary compact" type="button" data-permissions-all>Selectează tot</button></div><div class="permission-grid"><?php foreach($byGroup as $prefix=>$entries): ?><fieldset><legend><?= e($groups[$prefix]??ucfirst($prefix)) ?></legend><?php foreach($entries as $permission): ?><label class="permission-check"><input type="checkbox" name="permissions[]" value="<?= (int)$permission['id'] ?>" <?= in_array((int)$permission['id'],$selected,true)?'checked':'' ?>><span><strong><?= e($permission['label']) ?></strong><small><?= e($permission['name']) ?></small></span></label><?php endforeach; ?></fieldset><?php endforeach; ?></div></section></div><aside><section class="admin-panel staff-publish"><p class="eyebrow">PASUL 3</p><h2>Starea contului</h2><label>Status<select name="status"><option value="active" <?= ($user['status']??'active')==='active'?'selected':'' ?>>Activ — se poate conecta</option><option value="blocked" <?= ($user['status']??'')==='blocked'?'selected':'' ?>>Blocat — acces oprit</option></select></label><div class="staff-safety"><strong>Recomandare</strong><p>Nu oferi acces la setările magazinului decât unei persoane de încredere.</p></div><button class="admin-button" type="submit"><?= $editing?'Salvează modificările':'Creează utilizatorul' ?></button></section></aside></form>
<script>document.querySelector('[data-permissions-all]')?.addEventListener('click',event=>{const boxes=[...document.querySelectorAll('input[name="permissions[]"]')];const all=boxes.every(box=>box.checked);boxes.forEach(box=>box.checked=!all);event.currentTarget.textContent=all?'Selectează tot':'Deselectează tot';});</script>